const e=JSON.parse('{"key":"v-67c9b0bc","path":"/posts/%E9%91%AB%E5%8D%8E%E6%80%92%E6%94%BE/%E9%AD%94%E6%B3%95%E5%B8%88%E5%92%8C%E6%88%91.html","title":"魅魔雾气中魅惑晶核提取及解魅剂的制备","lang":"en-US","frontmatter":{"icon":"pen-to-square","date":"2023-01-07T00:00:00.000Z","category":["同人文"],"tag":["魔法学院报告"],"description":"魅魔雾气中魅惑晶核提取及解魅剂的制备 实验目的 了解魅魔雾气的主要成分，掌握提纯魅惑晶核的方法； 掌握利用具人化魅魔唾液和桃心尾端制备解魅剂的方法； 练习气气分离和雾气凝华等基本实验技能。 实验原理 魅魔是地狱魔鬼的一种，特殊无定形外貌，看起来像一团飘动的五颜六色雾气。在猎物引起它们注意的情况下，魅魔会凝聚形成与猎物心上人相似的样子。魅魔雾气中含有麻醉因子和魅惑晶核，前者会导致猎物全身肌肉松弛，后者引起猎物燥热难耐且精神恍惚。倘若未及时用法术清理呼吸道，几分钟后猎物会感到性兴奋，并在梦幻中感到心上人在与自己交媾。","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/blog/posts/%E9%91%AB%E5%8D%8E%E6%80%92%E6%94%BE/%E9%AD%94%E6%B3%95%E5%B8%88%E5%92%8C%E6%88%91.html"}],["meta",{"property":"og:site_name","content":"Delores0217"}],["meta",{"property":"og:title","content":"魅魔雾气中魅惑晶核提取及解魅剂的制备"}],["meta",{"property":"og:description","content":"魅魔雾气中魅惑晶核提取及解魅剂的制备 实验目的 了解魅魔雾气的主要成分，掌握提纯魅惑晶核的方法； 掌握利用具人化魅魔唾液和桃心尾端制备解魅剂的方法； 练习气气分离和雾气凝华等基本实验技能。 实验原理 魅魔是地狱魔鬼的一种，特殊无定形外貌，看起来像一团飘动的五颜六色雾气。在猎物引起它们注意的情况下，魅魔会凝聚形成与猎物心上人相似的样子。魅魔雾气中含有麻醉因子和魅惑晶核，前者会导致猎物全身肌肉松弛，后者引起猎物燥热难耐且精神恍惚。倘若未及时用法术清理呼吸道，几分钟后猎物会感到性兴奋，并在梦幻中感到心上人在与自己交媾。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"en-US"}],["meta",{"property":"article:author","content":"Mr.Hope"}],["meta",{"property":"article:tag","content":"魔法学院报告"}],["meta",{"property":"article:published_time","content":"2023-01-07T00:00:00.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"魅魔雾气中魅惑晶核提取及解魅剂的制备\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2023-01-07T00:00:00.000Z\\",\\"dateModified\\":null,\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Mr.Hope\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":2,"title":"实验目的","slug":"实验目的","link":"#实验目的","children":[]},{"level":2,"title":"实验原理","slug":"实验原理","link":"#实验原理","children":[]},{"level":2,"title":"实验仪器及试剂","slug":"实验仪器及试剂","link":"#实验仪器及试剂","children":[]},{"level":2,"title":"操作方法与实验步骤","slug":"操作方法与实验步骤","link":"#操作方法与实验步骤","children":[]},{"level":2,"title":"实验结果","slug":"实验结果","link":"#实验结果","children":[]},{"level":2,"title":"讨论","slug":"讨论","link":"#讨论","children":[]}],"git":{"createdTime":null,"updatedTime":null,"contributors":[]},"readingTime":{"minutes":2.9,"words":870},"filePathRelative":"posts/鑫华怒放/魔法师和我.md","localizedDate":"January 7, 2023","excerpt":"<h1> 魅魔雾气中魅惑晶核提取及解魅剂的制备</h1>\\n<h2> 实验目的</h2>\\n<ol>\\n<li>了解魅魔雾气的主要成分，掌握提纯魅惑晶核的方法；</li>\\n<li>掌握利用具人化魅魔唾液和桃心尾端制备解魅剂的方法；</li>\\n<li>练习气气分离和雾气凝华等基本实验技能。</li>\\n</ol>\\n<h2> 实验原理</h2>\\n<p>魅魔是地狱魔鬼的一种，特殊无定形外貌，看起来像一团飘动的五颜六色雾气。在猎物引起它们注意的情况下，魅魔会凝聚形成与猎物心上人相似的样子。魅魔雾气中含有麻醉因子和魅惑晶核，前者会导致猎物全身肌肉松弛，后者引起猎物燥热难耐且精神恍惚。倘若未及时用法术清理呼吸道，几分钟后猎物会感到性兴奋，并在梦幻中感到心上人在与自己交媾。</p>","autoDesc":true}');export{e as data};
